mapper.select:
/* com.shop.mapper.frontWeb.display.selectProductInfoListForEnumPaging */ SELECT TPD.ID AS prodDetId , TPD.PRODUCT_DET_COLOR AS prodDetColor , TP.ID AS prodId , TP.PROD_NM AS prodNm , TP.SELL_AMT AS sellAmt , TP.DISCOUNT_RATE AS discountRate , FD.SYS_FILE_NM AS sysFileNm FROM TB_PRODUCT_DET TPD JOIN TB_PRODUCT TP ON TP.ID = TPD.PRODUCT_ID AND TP.DEL_YN = 'N' JOIN TB_FILE_DET FD ON FD.FILE_ID = TPD.FILE_ID AND FD.FILE_SEQ = 1 AND FD.DEL_YN = 'N'
AND TPD.DEL_YN = 'N' AND TPD.IS_REP = true
AND TPD.ID > #{filter.lastProdDetId}
ORDER BY TPD.ID LIMIT #{pageRowCount} + 1;
